from flask import Flask, request, jsonify
import bcrypt
import re
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

users = {}

@app.route("/login", methods=["POST"])
def login():
    email = request.form["email"]
    password = request.form["password"]
    user = users[email]
    if bcrypt.checkpw(password.encode(), user["hash"].encode()):
        session["user_id"] = user["id"]
        return jsonify({"message": "Logged in successfully"}), 200
    else:
        return jsonify({"error": "Invalid email or password"}), 401

@app.route("/reset-mfa", methods=["POST"])
def reset_mfa():
    email = request.form["email"]
    if email in users:
        user = users[email]
        user["mfa_enabled"] = False
        return jsonify({"message": "MFA disabled successfully"}), 200
    else:
        return jsonify({"error": "Email not found"}), 401

@app.route("/verify-email", methods=["POST"])
def verify_email():
    email = request.form["email"]
    if email in users:
        user = users[email]
        if user["mfa_enabled"]:
            return jsonify({"message": "MFA enabled for this email"}), 200
        else:
            return jsonify({"error": "MFA not enabled for this email"}), 401
    else:
        return jsonify({"error": "Email not found"}), 401

@app.route("/send-reset-link", methods=["POST"])
def send_reset_link():
    email = request.form["email"]
    if email in users:
        user = users[email]
        reset_token = bcrypt.hashpw(user["id"], bcrypt.gensalt()).decode()
        url = f"https://www.example.com/reset-mfa?token={reset_token}"
        msg = MIMEText(f"""Hello {email},

You requested to reset your MFA settings for this account. Please click on the following link to proceed:
{url}

Best regards,
The Example Team""")
        msg["Subject"] = "Reset Your MFA Settings"
        msg["From"] = "noreply@example.com"
        s = smtplib.SMTP("smtp.example.com", 587)
        s.starttls()
        s.login(msg["From"], "password")
        s.sendmail(msg["From"], [email], msg.as_string())
        s.quit()
        return jsonify({"message": "Reset link sent to your email"}), 200
    else:
        return jsonify({"error": "Email not found"}), 401

